    float roughness;
    float metallic;
    float _pad0;
    float _pad1;
    vec2  tiling;
    vec2  _pad2;
};

out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    // Port the HLSL checker + material blend below
    /* ??? */
    fragColor = vec4(col, 1.0);
}

challenges.solution:
uniform vec2 u_resolution;

layout(std140) uniform Material {
    vec4  baseColor;
    float roughness;
    float metallic;
    float _pad0;
    float _pad1;
    vec2  tiling;
    vec2  _pad2;
};

out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 tiledUV = uv * tiling;
    float checker = fract(tiledUV.x) < 0.5 ? 1.0 : 0.0;
    checker = (checker != (fract(tiledUV.y) < 0.5 ? 1.0 : 0.0)) ? 1.0 : 0.0;
    vec3 col = baseColor.rgb * (0.5 + 0.5 * checker);
    col = mix(col, vec3(metallic), roughness);
    fragColor = vec4(col, 1.0);
}

hlsl.code:
cbuffer Material : register(b0) {
    float4 baseColor;
    float  roughness;
    float  metallic;
    float2 tiling;
};

float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float2 tiledUV = uv * tiling;
    float checker = frac(tiledUV.x) < 0.5 ? 1.0 : 0.0;
    checker       = checker != (frac(tiledUV.y) < 0.5 ? 1.0 : 0.0) ? 1.0 : 0.0;
    float3 col = baseColor.rgb * (0.5 + 0.5 * checker);
    col = lerp(col, float3(metallic, metallic, metallic), roughness);
    return float4(col, 1.0);
}

slang.code:
struct Material {
    float4 baseColor;
    float  roughness;
    float  metallic;
    float2 tiling;
};

uniform ParameterBlock<Material> gMaterial;

[shader("fragment")]
float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float2 tiledUV = uv * gMaterial.tiling;
    float checker = frac(tiledUV.x) < 0.5 ? 1.0 : 0.0;
    checker = checker != (frac(tiledUV.y) < 0.5 ? 1.0 : 0.0) ? 1.0 : 0.0;
    float3 col = gMaterial.baseColor.rgb * (0.5 + 0.5 * checker);
    col = lerp(col, float3(gMaterial.metallic), gMaterial.roughness);
    return float4(col, 1.0);
}

challenges.description:
In HLSL, textures and samplers are separate objects. A Texture2D is bound to a 't' register and a SamplerState to an 's' register. Sampling uses the .Sample() method. In GLSL, the texture and sampler are combined into a single sampler2D uniform, and sampling uses the texture() function.

Port the HLSL textured quad below to GLSL ES 3.0.

HLSL to port:
```hlsl
Texture2D    gAlbedo  : register(t0);
SamplerState gSampler : register(s0);

cbuffer Uniforms : register(b0) {
    float u_time;
};

float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float2 animUV = uv + float2(0.05 * sin(u_time), 0.0);
    float4 color  = gAlbedo.Sample(gSampler, animUV);
    return color;
}
```

Note: use `v_uv` from the quad vertex shader (not `vUV`).

