challenges.solution:
uniform sampler2D u_albedo;
uniform float     u_time;
uniform vec2      u_resolution;

in vec2 v_uv;
out vec4 fragColor;

void main() {
    vec2 animUV = v_uv + vec2(0.05 * sin(u_time), 0.0);
    vec4 color  = texture(u_albedo, animUV);
    fragColor = color;
}

hlsl.code:
Texture2D    gAlbedo  : register(t0);
SamplerState gSampler : register(s0);

cbuffer Uniforms : register(b0) {
    float u_time;
};

float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float2 animUV = uv + float2(0.05 * sin(u_time), 0.0);
    float4 color  = gAlbedo.Sample(gSampler, animUV);
    return color;
}

slang.code:
Texture2D    gAlbedo;
SamplerState gSampler;
uniform float u_time;

[shader("fragment")]
float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float2 animUV = uv + float2(0.05 * sin(u_time), 0.0);
    return gAlbedo.Sample(gSampler, animUV);
}

