challenges.solution:
in vec2 v_uv;
out vec4 fragColor;

void main() {
    // Simulate wave lane visualization using UV as proxy for lane index
    float laneIndex = floor(v_uv.x * 32.0);        // which 'lane' (0..31)
    float laneT     = fract(v_uv.x * 32.0);        // position within lane

    // Color each lane with a hue derived from its index
    float hue = laneIndex / 32.0;
    vec3 col = vec3(
        0.5 + 0.5 * sin(hue * 6.2832),
        0.5 + 0.5 * sin(hue * 6.2832 + 2.094),
        0.5 + 0.5 * sin(hue * 6.2832 + 4.189)
    );

    // Draw a lane boundary line
    if (laneT < 0.05) {
        col = vec3(0.0);
    }

    fragColor = vec4(col, 1.0);
}

hlsl.code:
[numthreads(32, 1, 1)]
void csMain(uint3 id : SV_DispatchThreadID,
            RWBuffer<float4> output : register(u0)) {
    uint  laneIdx   = WaveGetLaneIndex();
    uint  laneCount = WaveGetLaneCount();
    float hue       = float(laneIdx) / float(laneCount);
    float r = 0.5 + 0.5 * sin(hue * 6.2832);
    float g = 0.5 + 0.5 * sin(hue * 6.2832 + 2.094);
    float b = 0.5 + 0.5 * sin(hue * 6.2832 + 4.189);
    output[id.x] = float4(r, g, b, 1.0);
}

slang.code:
